using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PersonTests
    {
        // Concrete subclass to test abstract Person
        private class TestPerson : Person { }

        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var person = new TestPerson { LastName = "Smith", FirstMidName = "John" };
            Assert.Equal("Smith, John", person.FullName);
        }

        [Fact]
        public void FullName_WithEmptyNames_StillFormatsCorrectly()
        {
            var person = new TestPerson { LastName = "", FirstMidName = "" };
            Assert.Equal(", ", person.FullName);
        }

        [Fact]
        public void ID_DefaultsToZero()
        {
            var person = new TestPerson();
            Assert.Equal(0, person.ID);
        }

        [Fact]
        public void LastName_IsRequired()
        {
            var person = new TestPerson { FirstMidName = "John" };
            var results = new List<ValidationResult>();
            var context = new ValidationContext(person);
            Validator.TryValidateObject(person, context, results, true);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "LastName"));
        }

        [Fact]
        public void FirstMidName_IsRequired()
        {
            var person = new TestPerson { LastName = "Smith" };
            var results = new List<ValidationResult>();
            var context = new ValidationContext(person);
            Validator.TryValidateObject(person, context, results, true);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "FirstMidName"));
        }

        [Fact]
        public void LastName_MaxLength50_FailsWhenExceeded()
        {
            var person = new TestPerson { LastName = new string('A', 51), FirstMidName = "John" };
            var results = new List<ValidationResult>();
            var context = new ValidationContext(person);
            Validator.TryValidateObject(person, context, results, true);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "LastName"));
        }

        [Fact]
        public void FirstMidName_MaxLength50_FailsWhenExceeded()
        {
            var person = new TestPerson { LastName = "Smith", FirstMidName = new string('A', 51) };
            var results = new List<ValidationResult>();
            var context = new ValidationContext(person);
            Validator.TryValidateObject(person, context, results, true);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "FirstMidName"));
        }

        [Fact]
        public void ValidPerson_PassesValidation()
        {
            var person = new TestPerson { LastName = "Smith", FirstMidName = "John" };
            var results = new List<ValidationResult>();
            var context = new ValidationContext(person);
            var isValid = Validator.TryValidateObject(person, context, results, true);
            Assert.True(isValid);
            Assert.Empty(results);
        }
    }

    public class StudentTests
    {
        [Fact]
        public void Student_InheritsPerson()
        {
            var student = new Student();
            Assert.IsAssignableFrom<Person>(student);
        }

        [Fact]
        public void Student_EnrollmentDate_Required()
        {
            var student = new Student { LastName = "Smith", FirstMidName = "John" };
            // default DateTime is 0001-01-01 which is out of range
            var results = new List<ValidationResult>();
            var context = new ValidationContext(student);
            Validator.TryValidateObject(student, context, results, true);
            // Should fail because default DateTime is outside the 1753-9999 range
