using System;
using System.Linq;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from other tests (static queue)
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain queue to avoid polluting other tests
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("TestUser", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_UsesDisplayNameInMessage()
        {
            _service.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("John Smith", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("42", notification.Message);
            Assert.Contains("Student", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_MessageContainsCreated()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("created", notification.Message);
            Assert.Contains("Chemistry", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_MessageContainsUpdated()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_MessageContainsDeleted()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, null);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_FIFO_Order()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.SendNotification("Student", "2", EntityOperation.UPDATE);
            _service.SendNotification("Student", "3", EntityOperation.DELETE);

            Assert.Equal("1", _service.ReceiveNotification().EntityId);
            Assert.Equal("2", _service.ReceiveNotification().EntityId);
            Assert.Equal("3", _service.ReceiveNotification().EntityId);
            Assert.Null(_service.ReceiveNotification());
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op in the in-memory implementation
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void MarkAsRead_WithAnyId_DoesNotThrow()
        {
            _service.MarkAsRead(0);
            _service.MarkAsRead(-1);
            _service.MarkAsRead(int.MaxValue);
        }

        [Fact]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            var service = new NotificationService();
            service.Dispose();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName_Works()
        {
            _service.SendNotification("Department", "5", EntityOperation.UPDATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Department", notification.EntityType);
            Assert.Equal("5", notification.EntityId);
            Assert.Equal("UPDATE", notification.Operation);
        }

        [Fact]
        public void SendNotification_MultipleNotifications_AllReceived()
        {
            for (int i = 0; i < 20; i++)
            {
                _service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            int count = 0;
            while (_service.ReceiveNotification() != null)
            {
                count++;
            }
            Assert.Equal(20, count);
        }

        [Fact]
        public void SendNotification_EmptyDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "42", "", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_WhitespaceDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "42", "   ", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("ID: 42", notification.Message);
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 2, 3);
            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_CalculatesTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 1, 3);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        }

        [Fact]
        public void Constructor_TotalPages_ExactDivision()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 9, 1, 3);
            Assert.Equal(3, list.TotalPages); // ceil(9/3) = 3
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 10, 1, 5);
            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
            Assert.Contains("b", list);
            Assert.Contains("c", list);
        }

        [Fact]
        public void HasPreviousPage_ReturnsFalse_WhenOnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_ReturnsTrue_WhenNotOnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.True(list.HasNextPage); // TotalPages = 2, PageIndex = 1
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.False(list.HasNextPage); // TotalPages = 2, PageIndex = 2
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenSinglePage()
        {
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);
            Assert.False(list.HasNextPage); // TotalPages = 1, PageIndex = 1
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(3, result.TotalPages); // ceil(25/10) = 3
            Assert.Equal(10, result.Count);
            Assert.Equal(11, result.First());
            Assert.Equal(20, result.Last());
        }

        [Fact]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.First());
            Assert.Equal(10, result.Last());
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(3, result.PageIndex);
            Assert.Equal(5, result.Count);
            Assert.Equal(21, result.First());
            Assert.Equal(25, result.Last());
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
        }

        [Fact]
        public void Create_SingleItem_SinglePage()
        {
            var source = new[] { 42 }.AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Single(result);
            Assert.Equal(42, result[0]);
            Assert.Equal(1, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }
    }
}

