using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new NotificationsController(_context);
        }

        public void Dispose()
        {
            // Drain static queue
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
            service.Dispose();

            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithZeroCount()
        {
            // Drain any existing notifications
            var drainService = new NotificationService();
            while (drainService.ReceiveNotification() != null) { }

            var result = _controller.GetNotifications();
            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Drain first
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }

            // Add some notifications
            service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
            service.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE);

            var result = _controller.GetNotifications();
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }

            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            // First call should get 10
            var result = _controller.GetNotifications();
            Assert.IsType<JsonResult>(result);

            // The remaining 5 should still be in queue
            int remaining = 0;
            while (service.ReceiveNotification() != null) remaining++;
            Assert.Equal(5, remaining);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }
    }
}

