using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ViewModelTests
    {
        [Fact]
        public void AssignedCourseData_PropertiesWork()
        {
            var data = new AssignedCourseData
            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };
            Assert.Equal(1050, data.CourseID);
            Assert.Equal("Chemistry", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void AssignedCourseData_DefaultAssigned_IsFalse()
        {
            var data = new AssignedCourseData();
            Assert.False(data.Assigned);
        }

        [Fact]
        public void EnrollmentDateGroup_PropertiesWork()
        {
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = new DateTime(2020, 9, 1),
                StudentCount = 5
            };
            Assert.Equal(new DateTime(2020, 9, 1), group.EnrollmentDate);
            Assert.Equal(5, group.StudentCount);
        }

        [Fact]
        public void EnrollmentDateGroup_EnrollmentDate_IsNullable()
        {
            var group = new EnrollmentDateGroup();
            Assert.Null(group.EnrollmentDate);
        }

        [Fact]
        public void InstructorIndexData_PropertiesWork()
        {
            var data = new InstructorIndexData
            {
                Instructors = new List<Instructor>
                {
                    new Instructor { LastName = "Smith", FirstMidName = "John", HireDate = DateTime.Now }
                },
                Courses = new List<Course>
                {
                    new Course { Title = "Chemistry", Credits = 3 }
                },
                Enrollments = new List<Enrollment>
                {
                    new Enrollment { Grade = Grade.A }
                }
            };
            Assert.Single(data.Instructors);
            Assert.Single(data.Courses);
            Assert.Single(data.Enrollments);
        }

        [Fact]
        public void InstructorIndexData_DefaultProperties_AreNull()
        {
            var data = new InstructorIndexData();
            Assert.Null(data.Instructors);
            Assert.Null(data.Courses);
            Assert.Null(data.Enrollments);
        }
    }
}

