using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index(null, null, null, null);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.True(model.Count >= 2);
            // Default is ascending by LastName
            for (int i = 1; i < model.Count; i++)
            {
                Assert.True(string.Compare(model[i - 1].LastName, model[i].LastName, StringComparison.Ordinal) <= 0);
            }
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            for (int i = 1; i < model.Count; i++)
            {
                Assert.True(string.Compare(model[i - 1].LastName, model[i].LastName, StringComparison.Ordinal) >= 0);
            }
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            for (int i = 1; i < model.Count; i++)
            {
                Assert.True(model[i - 1].EnrollmentDate <= model[i].EnrollmentDate);
            }
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            for (int i = 1; i < model.Count; i++)
            {
                Assert.True(model[i - 1].EnrollmentDate >= model[i].EnrollmentDate);
            }
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Meredith", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
            Assert.Equal("Alonso", model[0].LastName);
        }

        [Fact]
        public void Index_SearchString_ResetsPage()
        {
            var result = _controller.Index(null, null, "Alexander", 3) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.Single(model);
        }

        [Fact]
        public void Index_EmptySearch_ReturnsAll()
        {
            var result = _controller.Index(null, null, "", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_SetsViewBagSortParameters()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_DateSortOrder_SetsDateSortParmToDateDesc()
        {
            _controller.Index("Date", null, null, null);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        // --- Details ---

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_WithValidId_ReturnsViewWithStudent()
        {
            var student = _context.Students.First();
            var result = _controller.Details(student.ID) as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        // --- Create GET ---

        [Fact]
        public void CreateGet_ReturnsViewWithStudent()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate.Date);
        }

        // --- Create POST ---

        [Fact]
        public void CreatePost_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var result = _controller.Create(student);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void CreatePost_ValidStudent_AddsToDatabase()
        {
            var initialCount = _context.Students.Count();
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Brand",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            _controller.Create(student);
            Assert.Equal(initialCount + 1, _context.Students.Count());
            Assert.Contains(_context.Students, s => s.LastName == "NewStudent");
        }

        [Fact]
        public void CreatePost_DefaultDate_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;
            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void CreatePost_DateBefore1753_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = _controller.Create(student) as ViewResult;
            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void CreatePost_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var result = _controller.Create(student) as ViewResult;
            Assert.NotNull(result);
        }

        // --- Edit GET ---

        [Fact]
        public void EditGet_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void EditGet_WithValidId_ReturnsViewWithStudent()
        {
            var student = _context.Students.First();
            var result = _controller.Edit(student.ID) as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        [Fact]
        public void EditGet_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Edit POST ---

        [Fact]
        public void EditPost_ValidStudent_RedirectsToIndex()
        {
            var student = _context.Students.First();
            student.LastName = "Updated";
            student.EnrollmentDate = new DateTime(2020, 1, 1);

            // Detach so EF doesn't track the same entity twice
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(student);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void EditPost_InvalidDate_ReturnsView()
        {
            var student = _context.Students.First();
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            student.EnrollmentDate = DateTime.MinValue;

            var result = _controller.Edit(student) as ViewResult;
            Assert.NotNull(result);
        }

        [Fact]
        public void EditPost_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 1,
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var result = _controller.Edit(student) as ViewResult;
            Assert.NotNull(result);
        }

        // --- Delete GET ---

        [Fact]
        public void DeleteGet_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void DeleteGet_WithValidId_ReturnsViewWithStudent()
        {
