using System;
using System.IO;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1050) as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(1050, model.CourseID);
            Assert.Equal("Chemistry", model.Title);
        }

        // --- Create GET ---

        [Fact]
        public void CreateGet_ReturnsViewWithEmptyCourse()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            Assert.IsType<Course>(result.Model);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        // --- Create POST ---

        [Fact]
        public void CreatePost_ValidCourse_NoFile_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var result = _controller.Create(course, null);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void CreatePost_ValidCourse_SavesInDatabase()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "Database Course",
                Credits = 4,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            _controller.Create(course, null);
            Assert.Contains(_context.Courses, c => c.CourseID == 8888);
        }

        [Fact]
        public void CreatePost_InvalidExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 7777,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.exe");
            fileMock.Setup(f => f.Length).Returns(1024);

            var result = _controller.Create(course, fileMock.Object) as ViewResult;
            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void CreatePost_FileTooLarge_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 7776,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.jpg");
            fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, fileMock.Object) as ViewResult;
            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void CreatePost_ValidImage_SavesFileAndPath()
        {
            var course = new Course
            {
                CourseID = 6666,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var content = new byte[] { 0x89, 0x50, 0x4E, 0x47 }; // fake PNG header
            var stream = new MemoryStream(content);
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("material.png");
            fileMock.Setup(f => f.Length).Returns(content.Length);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => stream.CopyTo(s));

            var result = _controller.Create(course, fileMock.Object);
            Assert.IsType<RedirectToActionResult>(result);

            var saved = _context.Courses.Find(6666);
            Assert.NotNull(saved.TeachingMaterialImagePath);
            Assert.StartsWith("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
        }

        [Fact]
        public void CreatePost_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 5555, Credits = 3 };

            var result = _controller.Create(course, null) as ViewResult;
            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Theory]
        [InlineData(".jpg")]
        [InlineData(".jpeg")]
        [InlineData(".png")]
        [InlineData(".gif")]
        [InlineData(".bmp")]
        public void CreatePost_AllowedExtensions_AreAccepted(string ext)
        {
            var course = new Course
            {
                CourseID = 5550 + Math.Abs(ext.GetHashCode() % 100),
                Title = "Test Course",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            var content = new byte[] { 0x00 };
            var stream = new MemoryStream(content);
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns($"test{ext}");
            fileMock.Setup(f => f.Length).Returns(content.Length);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => stream.CopyTo(s));

            var result = _controller.Create(course, fileMock.Object);
            Assert.IsType<RedirectToActionResult>(result);
        }

        // --- Edit GET ---

        [Fact]
        public void EditGet_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void EditGet_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit((int?)1050) as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(1050, model.CourseID);
        }

        [Fact]
        public void EditGet_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit((int?)99999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Edit POST ---

        [Fact]
        public void EditPost_ValidCourse_NoFile_RedirectsToIndex()
        {
            var course = _context.Courses.First();
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            course.Title = "Updated Title";

            var result = _controller.Edit(course, null);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void EditPost_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, Credits = 3 };

            var result = _controller.Edit(course, null) as ViewResult;
            Assert.NotNull(result);
        }

        [Fact]
        public void EditPost_InvalidExtension_ReturnsViewWithError()
        {
            var course = _context.Courses.First();
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.pdf");
            fileMock.Setup(f => f.Length).Returns(1024);

            var result = _controller.Edit(course, fileMock.Object) as ViewResult;
            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void EditPost_FileTooLarge_ReturnsViewWithError()
        {
            var course = _context.Courses.First();
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.jpg");
            fileMock.Setup(f => f.Length).Returns(10 * 1024 * 1024);

            var result = _controller.Edit(course, fileMock.Object) as ViewResult;
            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        // --- Delete GET ---

        [Fact]
        public void DeleteGet_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void DeleteGet_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050) as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(1050, model.CourseID);
        }

        // --- DeleteConfirmed POST ---

        [Fact]
        public void DeleteConfirmed_RemovesCourse()
        {
            var initialCount = _context.Courses.Count();
            _controller.DeleteConfirmed(1050);
            Assert.Equal(initialCount - 1, _context.Courses.Count());
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(4022);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_WithImagePath_AttemptsFileDelete()
        {
            // Add a course with a fake image path
            var course = _context.Courses.Find(1045);
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test.png";
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(1045);
            Assert.IsType<RedirectToActionResult>(result);
        }
    }
}

