using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var dept = _context.Departments.First();
            var result = _controller.Details(dept.DepartmentID) as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Create GET ---

        [Fact]
        public void CreateGet_ReturnsView()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Create POST ---

        [Fact]
        public void CreatePost_ValidDepartment_RedirectsToIndex()
        {
            var department = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = DateTime.Parse("2020-09-01"),
                InstructorID = _context.Instructors.First().ID
            };

            var result = _controller.Create(department);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void CreatePost_ValidDepartment_SavesInDatabase()
        {
            var initialCount = _context.Departments.Count();
            var department = new Department
            {
                Name = "Physics",
                Budget = 150000,
                StartDate = DateTime.Parse("2020-09-01"),
                InstructorID = _context.Instructors.First().ID
            };

            _controller.Create(department);
            Assert.Equal(initialCount + 1, _context.Departments.Count());
        }

        [Fact]
        public void CreatePost_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { Budget = 100000, StartDate = DateTime.Now };

            var result = _controller.Create(department) as ViewResult;
            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Edit GET ---

        [Fact]
        public void EditGet_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void EditGet_ValidId_ReturnsViewWithDepartment()
        {
            var dept = _context.Departments.First();
            var result = _controller.Edit(dept.DepartmentID) as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
        }

        [Fact]
        public void EditGet_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Edit POST ---

        [Fact]
        public void EditPost_ValidDepartment_RedirectsToIndex()
        {
            var dept = _context.Departments.First();
            _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            dept.Name = "Updated English";

            var result = _controller.Edit(dept);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void EditPost_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department
            {
                DepartmentID = 1,
                Budget = 100000,
                StartDate = DateTime.Now
            };

            var result = _controller.Edit(dept) as ViewResult;
            Assert.NotNull(result);
        }

        // --- Delete GET ---

        [Fact]
        public void DeleteGet_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void DeleteGet_ValidId_ReturnsViewWithDepartment()
        {
            var dept = _context.Departments.First();
            var result = _controller.Delete(dept.DepartmentID) as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
        }

        [Fact]
        public void DeleteGet_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- DeleteConfirmed POST ---

        [Fact]
        public void DeleteConfirmed_RemovesDepartment()
        {
            var dept = _context.Departments.First();
            var initialCount = _context.Departments.Count();

            _controller.DeleteConfirmed(dept.DepartmentID);
            Assert.Equal(initialCount - 1, _context.Departments.Count());
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            var dept = _context.Departments.First();
            var result = _controller.DeleteConfirmed(dept.DepartmentID);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }
    }
}

