using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_NoSelection_ReturnsViewWithInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Instructors);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var instructor = _context.Instructors.First();
            var result = _controller.Index(instructor.ID, null) as ViewResult;
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            var result = _controller.Index(null, null) as ViewResult;
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            var instructors = model.Instructors.ToList();
            for (int i = 1; i < instructors.Count; i++)
            {
                Assert.True(string.Compare(instructors[i - 1].LastName, instructors[i].LastName, StringComparison.Ordinal) <= 0);
            }
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors.First();
            var result = _controller.Details(instructor.ID) as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Create GET ---

        [Fact]
        public void CreateGet_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.Empty(model.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void CreateGet_PopulatesCoursesViewBag()
        {
            _controller.Create();
            var courses = _controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
            Assert.Equal(3, courses.Count); // 3 courses in seed data
            Assert.All(courses, c => Assert.False(c.Assigned));
        }

        // --- Create POST ---

        [Fact]
        public void CreatePost_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1)
            };

            var result = _controller.Create(instructor, null);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void CreatePost_ValidInstructor_SavesInDatabase()
        {
            var initialCount = _context.Instructors.Count();
            var instructor = new Instructor
            {
                LastName = "Created",
                FirstMidName = "Newly",
                HireDate = new DateTime(2020, 1, 1)
            };

            _controller.Create(instructor, null);
            Assert.Equal(initialCount + 1, _context.Instructors.Count());
        }

        [Fact]
        public void CreatePost_WithSelectedCourses_CreatesCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "WithCourses",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1)
            };

            _controller.Create(instructor, new[] { "1050", "4022" });

            var saved = _context.Instructors.First(i => i.LastName == "WithCourses");
            var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
            Assert.Equal(2, assignments.Count);
        }

        [Fact]
        public void CreatePost_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null) as ViewResult;
            Assert.NotNull(result);
        }

        // --- Delete GET ---

        [Fact]
        public void DeleteGet_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void DeleteGet_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors.First();
            var result = _controller.Delete(instructor.ID) as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        [Fact]
        public void DeleteGet_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- DeleteConfirmed POST ---

        [Fact]
        public void DeleteConfirmed_RemovesInstructor()
        {
            // Use the instructor that's NOT an administrator to avoid FK issues
            var instructor = _context.Instructors.First();
            var initialCount = _context.Instructors.Count();

            _controller.DeleteConfirmed(instructor.ID);
            Assert.Equal(initialCount - 1, _context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            var instructor = _context.Instructors.First();
            var result = _controller.DeleteConfirmed(instructor.ID);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            // Find instructor who is department admin
            var dept = _context.Departments.First();
            var adminId = dept.InstructorID.Value;

            _controller.DeleteConfirmed(adminId);

            // Reload department
            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.Null(updatedDept.InstructorID);
        }
    }
}

